  ?child p:market_name ?market_name .
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Real_Estate_Reporters } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?market_name ?description WHERE {
  ?real_estate_reporters_markets a :Real_Estate_Reporters_Markets .
